#include <stdio.h>

int main() {
    int start, end;
    int sum = 0;

    // Read the start and end of the range from standard input
    if (scanf("%d %d", &start, &end) != 2) {
        // In a real-world scenario, you might add more robust error handling here.
        // For this exercise, we assume valid input.
        return 1; // Indicate an error if input reading fails
    }

    // Loop through each number in the specified range (inclusive)
    for (int i = start; i <= end; i++) {
        // Use a conditional statement to check if the current number is even
        // An even number has a remainder of 0 when divided by 2
        if (i % 2 == 0) {
            sum += i; // If it's even, add it to the total sum
        }
    }

    // Print the calculated sum to standard output, followed by a newline
    printf("%d\n", sum);

    return 0; // Indicate successful execution
}
